     1→"use client";
     2→
     3→import { useChat } from "@ai-sdk/react";
     4→import {
     5→  skipToken,
     6→  useQuery,
     7→  useQueryClient,
     8→} from "@tanstack/react-query";
     9→import {
    10→  DefaultChatTransport,
    11→  lastAssistantMessageIsCompleteWithToolCalls,
    12→} from "ai";
    13→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
    14→import type {
    15→  ImageModelId,
    16→  VideoModelId,
    17→} from "@/components/product/editor/agent/AgentModelSelector";
    18→import { AssetsSidebar } from "@/components/product/editor/agent/AssetsSidebar";
    19→import { ChatHistorySidebar } from "@/components/product/editor/agent/ChatHistorySidebar";
    20→import { ChatMessagesPanel } from "@/components/product/editor/agent/ChatMessagesPanel";
    21→import {
    22→  extractImagePollingData,
    23→  extractMediaUrls,
    24→  extractVideoPollingData,
    25→  extractVideoReplicatePollingData,
    26→} from "@/components/product/editor/agent/components/utils";
    27→import { getGlobalSystemInstructions } from "@/components/product/editor/agent/utils";
    28→import { useCredits } from "@/context/CreditProvider";
    29→import { useSidebar } from "@/context/SidebarContext";
    30→import { authClient } from "@/lib/auth-client";
    31→import {
    32→  generateCloudFrontUrl,
    33→  generateS3KeyFromPredictionId,
    34→} from "@/lib/utils/s3-common";
    35→import { useAgentChatStore } from "@/state/stores/agentChatStore";
    36→import {
    37→  type CanvasMedia,
    38→  useCanvasAgentBridge,
    39→} from "@/state/stores/canvasAgentBridge";
    40→import { useTRPC } from "@/trpc/client";
    41→import { type LocalChat, useAgentChat } from "@/hooks/chat/useAgentChat";
    42→
    43→export const ChatClient = ({
    44→  projectId,
    45→  isOpen,
    46→  setIsOpen,
    47→}: {
    48→  projectId: string;
    49→  isOpen: boolean;
    50→  setIsOpen: (isOpen: boolean) => void;
    51→}) => {
    52→const { refreshCredits, userDetails, loading } = useCredits();
    53→  const { data: session } = authClient.useSession();
    54→  const user = session?.user;
    55→  const { toggleSidebar } = useSidebar();
    56→  const userId = user?.id;
    57→
    58→  const executeCommand = useCanvasAgentBridge((store) => store.executeCommand);
    59→  const clearCanvasSelection = useCanvasAgentBridge(
    60→    (store) => store.clearSelection,
    61→  );
    62→  const registerSendMessage = useAgentChatStore(
    63→    (store) => store.registerSendMessage,
    64→  );
    65→  const [activeChatId, setActiveChatId] = useState<string | null>(() => {
    66→    if (typeof window === "undefined") return null;
    67→    return localStorage.getItem(`active-chat-${projectId}`);
    68→  });
    69→
    70→  // Local new chats (created with UUID, not yet on server)
    71→  // These get merged with server chats for display
    72→  const [localNewChats, setLocalNewChats] = useState<LocalChat[]>([]);
    73→
    74→  // Ref to hold the current chatId - prevents stale closures in useChat transport
    75→  const activeChatIdRef = useRef<string | null>(null);
    76→  activeChatIdRef.current = activeChatId;
    77→
    78→  const [currenttab, setCurrenttab] = useState<"chat" | "assets" | "history">(
    79→    "chat",
    80→  );
    81→
    82→  const [isSystemDialogOpen, setIsSystemDialogOpen] = useState(false);
    83→  const [globalSystemInstructions, setGlobalSystemInstructions] = useState("");
    84→
    85→  // Model selection state for Auto/Manual mode
    86→  const [isAutoMode, setIsAutoMode] = useState(true);
    87→  const [selectedImageModel, setSelectedImageModel] =
    88→    useState<ImageModelId>("seedream-4.5");
    89→  const [selectedVideoModel, setSelectedVideoModel] =
    90→    useState<VideoModelId>("veo3.1");
    91→
    92→  // Refs to hold model selection - prevents stale closures in useChat transport
    93→  const modelSelectionRef = useRef({
    94→    isAutoMode: true,
    95→    imageModel: "seedream-4.5" as ImageModelId,
    96→    videoModel: "veo3.1" as VideoModelId,
    97→  });
    98→  // Keep refs in sync with state
    99→  modelSelectionRef.current = {
   100→    isAutoMode,
   101→    imageModel: selectedImageModel,
   102→    videoModel: selectedVideoModel,
   103→  };
   104→
   105→  // tRPC for loading chats and messages
   106→  const trpc = useTRPC();
   107→  const queryClient = useQueryClient();
   108→
   109→  // Fetch all chats for the project (sorted by lastUsedAt desc from backend)
   110→  const { data: chatsData, isPending: isLoadingChats } = useQuery({
   111→    ...trpc.chat.getChats.queryOptions({ projectId }),
   112→    enabled: Boolean(projectId),
   113→  });
   114→
   115→  // Merge server chats with local new chats (local chats appear first as they're newest)
   116→  const allChats = useMemo(() => {
   117→    const serverChats = chatsData?.chats ?? [];
   118→    const serverChatIds = new Set(serverChats.map((c) => c.id));
   119→
   120→    // Filter out local chats that now exist on server (they've been created)
   121→    const pendingLocalChats = localNewChats.filter(
   122→      (c) => !serverChatIds.has(c.id),
   123→    );
   124→
   125→    // Local new chats first (newest), then server chats
   126→    return [...pendingLocalChats, ...serverChats];
   127→  }, [chatsData?.chats, localNewChats]);
   128→
   129→  // Show empty state when no chats exist after loading completes
   130→  const showEmptyState = !isLoadingChats && allChats.length === 0;
   131→
   132→  const serverChatsLength = chatsData?.chats?.length ?? 0;
   133→  const firstChatId = allChats[0]?.id ?? null;
   134→  const allChatsLength = allChats.length;
   135→
   136→  // Clean up local chats that now exist on server
   137→  useEffect(() => {
   138→    if (!chatsData?.chats) return;
   139→    const serverChatIds = new Set(chatsData.chats.map((c) => c.id));
   140→    setLocalNewChats((prev) => prev.filter((c) => !serverChatIds.has(c.id)));
   141→  }, [serverChatsLength]);
   142→
   143→  // Auto-select first chat when data loads and no chat is selected (and none in storage)
   144→  useEffect(() => {
   145→    if (!activeChatId && firstChatId) {
   146→      setActiveChatId(firstChatId);
   147→      localStorage.setItem(`active-chat-${projectId}`, firstChatId);
   148→    }
   149→  }, [activeChatId, firstChatId, projectId]);
   150→
   151→  // If active chat was deleted, fall back to first available
   152→  useEffect(() => {
   153→    if (!activeChatId || allChatsLength === 0) return;
   154→    const stillExists = allChats.some((c) => c.id === activeChatId);
   155→    if (!stillExists) {
   156→      setActiveChatId(allChats[0]?.id ?? null);
   157→    }
   158→  }, [activeChatId, allChatsLength, firstChatId]);
   159→
   160→  // Check if this is an optimistically added chat (not yet on server)
   161→  const isOptimisticChat = useMemo(() => {
   162→    if (!activeChatId) return true;
   163→    const serverChats = chatsData?.chats ?? [];
   164→    return !serverChats.some((c) => c.id === activeChatId);
   165→  }, [activeChatId, chatsData?.chats]);
   166→
   167→  // Fetch messages for the selected chat (skip for optimistic chats)
   168→  const {
   169→    data: chatData,
   170→    isPending: isLoadingMessages,
   171→    isSuccess: hasLoadedMessages,
   172→  } = useQuery({
   173→    ...trpc.chat.getMessages.queryOptions(
   174→      activeChatId && !isOptimisticChat ? { chatId: activeChatId } : skipToken,
   175→    ),
   176→    enabled: Boolean(activeChatId) && !isOptimisticChat,
   177→  });
   178→
   179→  // Get current selection from bridge
   180→  // Note: We use a selector to avoid re-rendering ChatClient on every selection change
   181→  // The ref will hold the latest value for the transport callback
   182→  const selectionRef = useRef<CanvasMedia[]>([]);
   183→  useCanvasAgentBridge(
   184→    useCallback((state) => {
   185→      selectionRef.current = state.selection;
   186→      return state.selection;
   187→    }, []),
   188→  );
   189→
   190→  const { messages, sendMessage, status, setMessages, stop , addToolApprovalResponse } = useChat({
   191→    id: projectId, // Use chatId for requests (existing or pre-generated)
   192→    transport: useMemo(
   193→      () =>
   194→        new DefaultChatTransport({
   195→          api: "/api/agents/v1",
   196→          body: () => {
   197→            const sel = modelSelectionRef.current;
   198→            const modelSelection = {
   199→              isAutoMode: sel.isAutoMode,
   200→              imageModel: sel.isAutoMode ? null : sel.imageModel,
   201→              videoModel: sel.isAutoMode ? null : sel.videoModel,
   202→            };
   203→
   204→            return {
   205→              globalSystemInstructions,
   206→              chatId: activeChatIdRef.current,
   207→              modelSelection,
   208→              selection: selectionRef.current, // Inject selection context
   209→            };
   210→          },
   211→          prepareSendMessagesRequest({
   212→            messages: requestMessages,
   213→            id: requestId,
   214→          }) {
   215→            const sel = modelSelectionRef.current;
   216→            const modelSelection = {
   217→              isAutoMode: sel.isAutoMode,
   218→              imageModel: sel.isAutoMode ? null : sel.imageModel,
   219→              videoModel: sel.isAutoMode ? null : sel.videoModel,
   220→            };
   221→
   222→            return {
   223→              body: {
   224→                message: requestMessages.at(-1),
   225→                id: requestId, // projectId
   226→                chatId: activeChatIdRef.current,
   227→                globalSystemInstructions,
   228→                modelSelection,
   229→                selection: selectionRef.current, // Inject selection context
   230→              },
   231→            };
   232→          },
   233→          // eslint-disable-next-line react-hooks/exhaustive-deps
   234→        }),
   235→      [],
   236→    ), // Stable transport, refs provide fresh values
   237→    sendAutomaticallyWhen: lastAssistantMessageIsCompleteWithToolCalls,
   238→    onToolCall({ toolCall }) {
   239→      if (toolCall.dynamic) {
   240→        return;
   241→      }
   242→    },
   243→    onFinish({ message }) {
   244→      refreshCredits();
   245→
   246→      // Invalidate chat list if this chat hasn't been synced yet
   247→      // This ensures isOptimisticChat becomes false after first message
   248→      const currentChatId = activeChatIdRef.current;
   249→      if (currentChatId && !syncedChatsRef.current.has(currentChatId)) {
   250→        syncedChatsRef.current.add(currentChatId);
   251→        queryClient.invalidateQueries({
   252→          queryKey: trpc.chat.getChats.queryKey({ projectId }),
   253→        });
   254→      }
   255→
   256→      // Add media from completed tool calls to canvas
   257→      if (message.role === "assistant" && message.parts) {
   258→        for (const part of message.parts) {
   259→          // Type guard: check if part is a tool part with output
   260→          const isToolPart =
   261→            typeof part === "object" &&
   262→            part !== null &&
   263→            "type" in part &&
   264→            typeof part.type === "string" &&
   265→            part.type.startsWith("tool-") &&
   266→            "state" in part &&
   267→            part.state === "output-available" &&
   268→            "output" in part &&
   269→            part.output !== undefined &&
   270→            "toolCallId" in part &&
   271→            typeof part.toolCallId === "string";
   272→
   273→          if (!isToolPart) continue;
   274→
   275→          const toolCallId = part.toolCallId;
   276→          const output = part.output;
   277→
   278→          // Skip if we've already processed this tool call
   279→          if (processedToolCallsRef.current.has(toolCallId)) {
   280→            continue;
   281→          }
   282→
   283→          // Mark as processed before attempting to add (prevents duplicates on retry)
   284→          processedToolCallsRef.current.add(toolCallId);
   285→
   286→          // Extract video polling data (videos that need polling)
   287→          const videoPollingData = extractVideoPollingData(output);
   288→          if (videoPollingData) {
   289→            // Generate S3 key/URL upfront using predictionId
   290→            const s3Key = generateS3KeyFromPredictionId(
   291→              videoPollingData.predictionId,
   292→              "video-generation",
   293→              0, // index for single video
   294→              ".mp4", // Video extension
   295→            );
   296→            const s3Url = generateCloudFrontUrl(s3Key);
   297→
   298→            // Extend polling data with S3 URL
   299→            const extendedVideoPollingData = {
   300→              ...videoPollingData,
   301→              s3Url,
   302→            };
   303→
   304→            const baseMetadata: Record<string, unknown> = {
   305→              source: "agent-chat",
   306→              mediaType: "video",
   307→              toolCallId,
   308→              chatId: activeChatIdRef.current,
   309→              projectId,
   310→              createdAt: new Date().toISOString(),
   311→              model: modelSelectionRef.current.isAutoMode
   312→                ? "auto"
   313→                : modelSelectionRef.current.videoModel,
   314→            };
   315→
   316→            executeCommand({
   317→              type: "add",
   318→              mediaType: "video",
   319→              objectId: `${toolCallId}-0`, // Generate stable ID (videos with polling are typically single)
   320→              pollingData: extendedVideoPollingData,
   321→              metadata: baseMetadata,
   322→            }).catch((error: unknown) => {
   323→              console.error("Failed to add video with polling:", error);
   324→              // Remove from processed set on error so it can be retried
   325→              processedToolCallsRef.current.delete(toolCallId);
   326→            });
   327→            continue;
   328→          }
   329→
   330→          // Extract video Replicate polling data (video upscaler and similar tools)
   331→          const videoReplicatePollingData =
   332→            extractVideoReplicatePollingData(output);
   333→          if (videoReplicatePollingData) {
   334→            // Extract tool name from part.type (e.g., "tool-videoLipSync" -> "videoLipSync")
   335→            // Then convert camelCase to kebab-case (e.g., "videoLipSync" -> "video-lip-sync")
   336→            const toolNameCamelCase = part.type.replace(/^tool-/, "");
   337→            const toolNameKebabCase = toolNameCamelCase
   338→              .replace(/([A-Z])/g, "-$1")
   339→              .toLowerCase()
   340→              .replace(/^-/, "");
   341→
   342→            // Generate S3 key/URL upfront using predictionId
   343→            const s3Key = generateS3KeyFromPredictionId(
   344→              videoReplicatePollingData.predictionId,
   345→              toolNameKebabCase,
   346→              0, // index for single video
   347→              ".mp4", // Video extension
   348→            );
   349→            const s3Url = generateCloudFrontUrl(s3Key);
   350→
   351→            // Extend polling data with S3 URL
   352→            const extendedVideoReplicatePollingData = {
   353→              ...videoReplicatePollingData,
   354→              s3Url,
   355→            };
   356→
   357→            const baseMetadata: Record<string, unknown> = {
   358→              source: "agent-chat",
   359→              mediaType: "video",
   360→              toolCallId,
   361→              chatId: activeChatIdRef.current,
   362→              projectId,
   363→              createdAt: new Date().toISOString(),
   364→              model: toolNameCamelCase || "video-upscaler",
   365→            };
   366→
   367→            executeCommand({
   368→              type: "add",
   369→              mediaType: "video",
   370→              objectId: `${toolCallId}-0`, // Generate stable ID
   371→              pollingData: extendedVideoReplicatePollingData,
   372→              metadata: baseMetadata,
   373→            }).catch((error: unknown) => {
   374→              console.error(
   375→                "Failed to add video with Replicate polling:",
   376→                error,
   377→              );
   378→              // Remove from processed set on error so it can be retried
   379→              processedToolCallsRef.current.delete(toolCallId);
   380→            });
   381→            continue;
   382→          }
   383→
   384→          // Extract image polling data (images that need polling)
   385→          const imagePollingData = extractImagePollingData(output);
   386→          if (imagePollingData) {
   387→            // Generate S3 key/URL upfront using predictionId
   388→            const s3Key = generateS3KeyFromPredictionId(
   389→              imagePollingData.predictionId,
   390→              "image-generation", // Default toolName, can be enhanced later
   391→              0, // index for single image
   392→              ".webp", // Default extension
   393→            );
   394→            const s3Url = generateCloudFrontUrl(s3Key);
   395→
   396→            // Extend polling data with S3 URL (s3Key not needed for persistence)
   397→            const extendedPollingData = {
   398→              ...imagePollingData,
   399→              s3Url,
   400→            };
   401→
   402→            const baseMetadata: Record<string, unknown> = {
   403→              source: "agent-chat",
   404→              mediaType: "image",
   405→              toolCallId,
   406→              chatId: activeChatIdRef.current,
   407→              projectId,
   408→              createdAt: new Date().toISOString(),
   409→              model: modelSelectionRef.current.isAutoMode
   410→                ? "auto"
   411→                : modelSelectionRef.current.imageModel,
   412→            };
   413→
   414→            executeCommand({
   415→              type: "add",
   416→              mediaType: "image",
   417→              objectId: `${toolCallId}-0`, // Generate stable ID (images with polling are typically single)
   418→              pollingData: extendedPollingData,
   419→              metadata: baseMetadata,
   420→            }).catch((error: unknown) => {
   421→              console.error("Failed to add image with polling:", error);
   422→              // Remove from processed set on error so it can be retried
   423→              processedToolCallsRef.current.delete(toolCallId);
   424→            });
   425→            continue;
   426→          }
   427→
   428→          // Extract regular media URLs (images and direct video URLs)
   429→          const media = extractMediaUrls(output);
   430→          if (media && media.type !== "audio") {
   431→            // Audio doesn't go to canvas, skip it
   432→            const mediaType = media.type as "image" | "video";
   433→
   434→            // Generate stable IDs: toolCallId + index (simple and reliable)
   435→            // CustomToolOutput generates the same IDs deterministically, no store needed
   436→            const stableIds = media.urls.map(
   437→              (_, index) => `${toolCallId}-${index}`,
   438→            );
   439→
   440→            // Add to canvas with stable IDs
   441→            const addPromises = media.urls.map((url: string, index: number) =>
   442→              executeCommand({
   443→                type: "add",
   444→                url,
   445→                mediaType,
   446→                objectId: stableIds[index], // Pass stable ID to canvas
   447→                metadata: {
   448→                  source: "agent-chat",
   449→                  mediaType,
   450→                  toolCallId,
   451→                  mediaIndex: index,
   452→                  chatId: activeChatIdRef.current,
   453→                  projectId,
   454→                  createdAt: new Date().toISOString(),
   455→                },
   456→              }),
   457→            );
   458→
   459→            Promise.all(addPromises).catch((error: unknown) => {
   460→              console.error("Failed to add media to canvas:", error);
   461→              // Remove from processed set on error so it can be retried
   462→              processedToolCallsRef.current.delete(toolCallId);
   463→            });
   464→          }
   465→        }
   466→      }
   467→    },
   468→    onError(error) {
   469→      console.error("Chat error:", error);
   470→      // Error will be displayed in the messages stream from server
   471→    },
   472→  });
   473→
   474→  // Use agent chat hook for chat management (after useChat so setMessages is available)
   475→  const {
   476→    handleNewChat,
   477→    handleSelectChat,
   478→    handleDeleteChat,
   479→    handleRenameChat,
   480→    hasSetMessagesRef,
   481→    lastChatIdRef,
   482→    processedToolCallsRef,
   483→    syncedChatsRef,
   484→  } = useAgentChat({
   485→    projectId,
   486→    activeChatId,
   487→    setActiveChatId,
   488→    setMessages,
   489→    setLocalNewChats,
   490→    setCurrenttab,
   491→    allChats,
   492→    chatsData,
   493→  });
   494→
   495→  // Register sendMessage for external components (e.g., MediaNodeToolbar)
   496→  useEffect(() => {
   497→    type MessagePart =
   498→      | { type: "text"; text: string }
   499→      | { type: "file"; url: string; mediaType: string; filename?: string };
   500→
   501→    const wrappedSendMessage = async (parts: MessagePart[]) => {
   502→      await sendMessage({ role: "user", parts });
   503→    };
   504→    registerSendMessage(wrappedSendMessage);
   505→    return () => registerSendMessage(null);
   506→  }, [sendMessage, registerSendMessage]);
   507→
   508→  // Load from localStorage when user changes
   509→  useEffect(() => {
   510→    setGlobalSystemInstructions(getGlobalSystemInstructions(userId));
   511→  }, [userId]);
   512→
   513→  // Track if chat was optimistic to detect transition to server chat
   514→  const wasOptimisticRef = useRef(isOptimisticChat);
   515→
   516→  const messagesLength = hasLoadedMessages
   517→    ? (chatData?.messages?.length ?? 0)
   518→    : 0;
   519→
   520→  // Set messages when tRPC query completes (or reset when chat changes)
   521→  useEffect(() => {
   522→    // Reset if chat changed
   523→    if (activeChatId !== lastChatIdRef.current) {
   524→      hasSetMessagesRef.current = false;
   525→      lastChatIdRef.current = activeChatId;
   526→      // Clear canvas selection when switching chats
   527→      clearCanvasSelection();
   528→    }
   529→
   530→    // Reset if chat transitioned from optimistic to server (messages now available from DB)
   531→    if (wasOptimisticRef.current && !isOptimisticChat) {
   532→      hasSetMessagesRef.current = false;
   533→    }
   534→    wasOptimisticRef.current = isOptimisticChat;
   535→
   536→    if (hasLoadedMessages && chatData?.messages && !hasSetMessagesRef.current) {
   537→      if (chatData.messages.length > 0) {
   538→        // Pre-populate processedToolCallsRef with tool calls from loaded messages
   539→        // to prevent re-processing when onFinish fires with accumulated parts
   540→        for (const msg of chatData.messages) {
   541→          if (msg.role === "assistant" && msg.parts) {
   542→            for (const part of msg.parts) {
   543→              if (
   544→                typeof part === "object" &&
   545→                part !== null &&
   546→                "toolCallId" in part &&
   547→                typeof part.toolCallId === "string"
   548→              ) {
   549→                processedToolCallsRef.current.add(part.toolCallId);
   550→              }
   551→            }
   552→          }
   553→        }
   554→        setMessages(chatData.messages);
   555→      }
   556→      hasSetMessagesRef.current = true;
   557→    }
   558→  }, [
   559→    hasLoadedMessages,
   560→    messagesLength,
   561→    setMessages,
   562→    activeChatId,
   563→    isOptimisticChat,
   564→    clearCanvasSelection,
   565→  ]);
   566→
   567→  // Dedupe messages by ID - ensures latest version wins during streaming updates with tool calls
   568→  // TODO: Uncomment this if we want to deduplicate messages
   569→  // const processedMessages = useMemo(() => {
   570→  //   const messageMap = new Map<string, UIMessage>();
   571→  //   for (const msg of messages) {
   572→  //     messageMap.set(msg.id, msg);
   573→  //   }
   574→  //   return Array.from(messageMap.values());
   575→  // }, [messages]);
   576→
   577→  // Seed chat with an initial prompt from the editor (if provided via localStorage).
   578→  // This is a one-time seed: the key is cleared immediately after use.
   579→  useEffect(() => {
   580→    // Don't send if messages already exist
   581→    if (messages.length > 0) return;
   582→
   583→    // Don't send if chats are still loading (wait for chat to be available)
   584→    if (isLoadingChats) return;
   585→
   586→    // Don't send if chatId is not ready yet
   587→    // If no chat exists after loading, create one first
   588→    if (!activeChatId) {
   589→      // If chats finished loading but no chat exists, create one
   590→      // The effect will run again when activeChatId is set
   591→      if (allChats.length === 0) {
