   401→/**
   402→ * Renders message parts with intelligent grouping
   403→ * - Groups consecutive images into grids
   404→ * - Renders other parts individually
   405→ */
   406→export default function MessagePartRenderer({
   407→  parts,
   408→  debugToolUi = true,
   409→  onAddImageToCanvas,
   410→}: MessagePartRendererProps) {
   411→  if (!parts || parts.length === 0) {
   412→    return null;
   413→  }
   414→
   415→  const renderedElements: React.ReactNode[] = [];
   416→  let i = 0;
   417→
   418→  while (i < parts.length) {
   419→    const part = parts[i];
   420→
   421→    // Check if this is the start of an image sequence
   422→    // Handle both type: "image" (old) and type: "file" with image mediaType (new)
   423→    const isImage =
   424→      (part.type === "image" && part.image) ||
   425→      (part.type === "file" &&
   426→        part.mediaType?.startsWith("image/") &&
   427→        part.url);
   428→
   429→    if (isImage) {
   430→      const imageUrls: string[] = [];
   431→      const startIndex = i;
   432→
   433→      // Collect consecutive images
   434→      while (i < parts.length) {
   435→        const currentPart = parts[i];
   436→        const isCurrentImage =
   437→          (currentPart.type === "image" && currentPart.image) ||
   438→          (currentPart.type === "file" &&
   439→            currentPart.mediaType?.startsWith("image/") &&
   440→            currentPart.url);
   441→
   442→        if (!isCurrentImage) break;
   443→
   444→        const imageUrl =
   445→          currentPart.type === "image" ? currentPart.image : currentPart.url;
   446→        if (imageUrl) imageUrls.push(imageUrl);
   447→        i += 1;
   448→      }
   449→
   450→      // Render grouped images
   451→      renderedElements.push(
   452→        renderImageGrid(imageUrls, startIndex, onAddImageToCanvas),
   453→      );
   454→    } else {
   455→      // Render non-image parts individually
   456→      const singlePart = renderSinglePart(part, i, debugToolUi);
   457→      if (singlePart) {
   458→        // Tools are already wrapped in MessageContent, so don't wrap again
   459→        const isTool = [
   460→          "tool-autoModelSuggest",
   461→          "tool-autoVideoModelSuggest",
   462→          "tool-GenerateImage",
   463→          "tool-GenerateVideo",
   464→          "tool-editImage",
   465→          "tool-generateImage",
   466→          "tool-generateVideo",
   467→          "tool-generateAudio",
   468→          "tool-removeBackground",
   469→          "tool-resizeImage",
   470→          "tool-upscaleImage",
   471→          "tool-videoLipSync",
   472→          "tool-videoAddAudio",
   473→          "tool-videoTrim",
   474→          "tool-videoSpeedChange",
   475→          "tool-videoStitch",
   476→          "tool-videoReframe",
   477→          "tool-videoUpscaler",
   478→          "dynamic-tool",
   479→        ].includes(part.type);
   480→
   481→        if (isTool) {
   482→          renderedElements.push(singlePart);
   483→        } else {
   484→          renderedElements.push(
   485→            <MessageContent key={i}>{singlePart}</MessageContent>,
   486→          );
   487→        }
   488→      }
   489→      i += 1;
   490→    }
   491→  }
   492→
   493→  return <div className="space-y-2">{renderedElements}</div>;
   494→}
