    32→const ImageWithFallback = ({
    33→  primaryUrl,
    34→  fallbackUrl,
    35→  ...imageProps
    36→}: {
    37→  primaryUrl: string;
    38→  fallbackUrl: string;
    39→} & Omit<React.ComponentProps<typeof Image>, "src">) => {
    40→  const [imgSrc, setImgSrc] = useState(primaryUrl);
    41→  const [hasTriedFallback, setHasTriedFallback] = useState(false);
    42→
    43→  // Reset state when primary URL changes
    44→  useEffect(() => {
    45→    setImgSrc(primaryUrl);
    46→    setHasTriedFallback(false);
    47→  }, [primaryUrl]);
    48→
    49→  return (
    50→    <Image
    51→      {...imageProps}
    52→      onError={() => {
    53→        if (!hasTriedFallback) {
    54→          setHasTriedFallback(true);
    55→          setImgSrc(fallbackUrl);
    56→        }
    57→      }}
    58→      src={imgSrc}
    59→    />
    60→  );
    61→};
