   229→type ToolState =
   230→  | "input-streaming"
   231→  | "input-available"
   232→  | "output-available"
   233→  | "output-error";
   234→
   235→/**
   236→ * CustomToolOutput - Renders tool outputs with UI feedback
   237→ *
   238→ * Note: Canvas addition happens in ChatClient's onFinish callback, not here.
   239→ * This component only handles UI rendering:
   240→ * - Images/Videos: Shows confirmation message when output is available
   241→ * - Audio: Renders audio player (audio doesn't go to canvas)
   242→ * - Other: Falls back to default ToolOutput
   243→ */
   244→const CustomToolOutput = ({
   245→  output,
   246→  errorText,
   247→  state,
   248→  toolCallId,
   249→}: {
   250→  output: unknown;
   251→  errorText?: string;
   252→  state?: ToolState;
   253→  toolCallId?: string;
   254→}) => {
   255→  const executeCommand = useCanvasAgentBridge((store) => store.executeCommand);
   256→
   257→  // Extract media from output (memoized to prevent unnecessary recalculations)
   258→  const media = useMemo(() => {
   259→    const result = extractMediaUrls(output);
   260→    if (!result) return null;
   261→
   262→    // Generate objectIds deterministically: toolCallId-index (same pattern as ChatClient)
   263→    const objectIds = toolCallId
   264→      ? result.urls.map((_, index) => `${toolCallId}-${index}`)
   265→      : undefined;
   266→
   267→    return { ...result, objectIds };
   268→  }, [output, toolCallId]);
   269→
   270→  // Extract video polling data (for videos that need polling - FalAI style with requestLink)
   271→  const videoPollingData = useMemo(
   272→    () => extractVideoPollingData(output),
   273→    [output],
   274→  );
   275→
   276→  // Extract Replicate-based video polling data (for video editing tools like trim, reframe, etc.)
   277→  const videoReplicatePollingData = useMemo(
   278→    () => extractVideoReplicatePollingData(output),
   279→    [output],
   280→  );
   281→
   282→  // Extract image polling data (for images that need polling)
   283→  const imagePollingData = useMemo(
   284→    () => extractImagePollingData(output),
   285→    [output],
   286→  );
   287→
   288→  // Use polling hooks to check completion status (always call hooks, conditionally use results)
   289→  const imagePollingResult = useCanvasImagePolling(
   290→    imagePollingData
   291→      ? {
   292→          predictionId: imagePollingData.predictionId,
   293→          provider: imagePollingData.provider,
   294→        }
   295→      : { predictionId: "", provider: "replicate" },
   296→  );
   297→
   298→  const videoPollingResult = useCanvasVideoPolling(
   299→    videoPollingData
   300→      ? {
   301→          predictionId: videoPollingData.predictionId,
   302→          requestLink: videoPollingData.requestLink,
   303→          provider: videoPollingData.provider,
   304→        }
   305→      : { predictionId: "", requestLink: "" },
   306→  );
   307→
   308→  // Use Replicate video polling for video editing tools (trim, reframe, speed change, etc.)
   309→  const videoReplicatePollingResult = useCanvasVideoPolling(
   310→    videoReplicatePollingData
   311→      ? {
   312→          predictionId: videoReplicatePollingData.predictionId,
   313→          provider: videoReplicatePollingData.provider,
   314→        }
   315→      : { predictionId: "", provider: "replicate" },
   316→  );
   317→
   318→  // Focus on canvas object by stable ID
   319→  const handleMediaClick = async (objectId: string, _index: number) => {
   320→    try {
   321→      await executeCommand({ type: "focus", objectId });
   322→    } catch {
   323→      // Silently fail if object not found or editor not ready
   324→    }
   325→  };
   326→
   327→  // Extract error from output object if it exists
   328→  const extractedError = useMemo(
   329→    () => extractErrorFromOutput(output),
   330→    [output],
   331→  );
   332→
   333→  // Use errorText prop or extracted error from output
   334→  const finalErrorText = errorText || extractedError;
   335→
   336→  // ─── Error State ───────────────────────────────────────────
   337→  // Show error if errorText is provided, error is extracted from output, or state indicates error
   338→  if (finalErrorText || state === "output-error") {
   339→    const errorMessage =
   340→      finalErrorText || "An error occurred while processing your request.";
   341→    const parsedError = parseError(errorMessage);
   342→
   343→    const errorConfig = {
   344→      insufficient_credits: {
   345→        icon: "💳",
   346→        title: "Insufficient Credits",
   347→        bgColor: "bg-yellow-500/10",
   348→        borderColor: "border-yellow-500/20",
   349→        textColor: "text-yellow-400",
   350→      },
   351→      nsfw: {
   352→        icon: "🚫",
   353→        title: "Content Policy",
   354→        bgColor: "bg-orange-500/10",
   355→        borderColor: "border-orange-500/20",
   356→        textColor: "text-orange-400",
   357→      },
   358→      unexpected_error: {
   359→        icon: "⚠",
   360→        title: "Error",
   361→        bgColor: "bg-red-500/10",
   362→        borderColor: "border-red-500/20",
   363→        textColor: "text-red-400",
   364→      },
   365→    }[parsedError.type];
   366→
   367→    return (
   368→      <div
   369→        className={`rounded-lg border ${errorConfig.borderColor} ${errorConfig.bgColor} p-3`}
   370→      >
   371→        <div className="flex items-start gap-2">
   372→          <span className={errorConfig.textColor}>{errorConfig.icon}</span>
   373→          <div className="flex-1">
   374→            <p className={`font-medium ${errorConfig.textColor} text-sm`}>
   375→              {errorConfig.title}
   376→            </p>
   377→            <p className={`mt-1 ${errorConfig.textColor} text-sm`}>
   378→              {parsedError.message}
   379→            </p>
   380→          </div>
   381→        </div>
   382→      </div>
   383→    );
   384→  }
   385→
   386→  // ─── No Output ─────────────────────────────────────────────
   387→  if (!output) {
   388→    return null;
   389→  }
   390→
   391→  // ─── Audio: Render in chat (doesn't go to canvas) ──────────
   392→  if (media?.type === "audio") {
   393→    return <AudioPlayer urls={media.urls} />;
   394→  }
   395→
   396→  // ─── Replicate Video Polling: For video editing tools (trim, reframe, etc.) ────
   397→  if (videoReplicatePollingData && state === "output-available") {
   398→    if (videoReplicatePollingResult.isError) {
   399→      const message = videoReplicatePollingResult.isNsfw
   400→        ? "Video blocked due to content policy"
   401→        : "Failed to process video";
   402→      const parsedErr = parseError(message);
   403→      const cfg = {
   404→        nsfw: {
   405→          icon: "🚫",
   406→          title: "Content Policy",
   407→          bgColor: "bg-orange-500/10",
   408→          borderColor: "border-orange-500/20",
   409→          textColor: "text-orange-400",
   410→        },
   411→        unexpected_error: {
   412→          icon: "⚠",
   413→          title: "Error",
   414→          bgColor: "bg-red-500/10",
   415→          borderColor: "border-red-500/20",
   416→          textColor: "text-red-400",
   417→        },
   418→        insufficient_credits: {
   419→          icon: "⚠",
   420→          title: "Error",
   421→          bgColor: "bg-red-500/10",
   422→          borderColor: "border-red-500/20",
   423→          textColor: "text-red-400",
   424→        },
   425→      }[parsedErr.type];
   426→      return (
   427→        <div
   428→          className={`rounded-lg border ${cfg.borderColor} ${cfg.bgColor} p-3`}
   429→        >
   430→          <div className="flex items-start gap-2">
   431→            <span className={cfg.textColor}>{cfg.icon}</span>
   432→            <div className="flex-1">
   433→              <p className={`font-medium ${cfg.textColor} text-sm`}>
   434→                {cfg.title}
   435→              </p>
   436→              <p className={`mt-1 ${cfg.textColor} text-sm`}>
   437→                {parsedErr.message}
   438→              </p>
   439→            </div>
   440→          </div>
   441→        </div>
   442→      );
   443→    }
   444→
   445→    const isComplete =
   446→      videoReplicatePollingResult.videoUrl &&
   447→      !videoReplicatePollingResult.isLoading;
   448→    const objectId = toolCallId ? `${toolCallId}-0` : undefined;
   449→
   450→    if (isComplete && videoReplicatePollingResult.videoUrl) {
   451→      // Show final video when polling completes
   452→      return (
   453→        <div className="space-y-2">
   454→          <VideoMediaRenderer
   455→            objectIds={objectId ? [objectId] : undefined}
   456→            onVideoClick={handleMediaClick}
   457→            urls={[videoReplicatePollingResult.videoUrl]}
   458→          />
   459→          <span className="">Video added to canvas</span>
   460→        </div>
   461→      );
   462→    }
   463→
   464→    // Show placeholder while polling
   465→    return (
   466→      <div className="space-y-2">
   467→        <VideoPollingPlaceholder />
   468→        <span className="">Video will be added to canvas when ready</span>
   469→      </div>
   470→    );
   471→  }
   472→
   473→  // ─── Video Polling: Show placeholder or final video (FalAI style) ────────────────────────
   474→  if (videoPollingData && state === "output-available") {
   475→    if (videoPollingResult.isError) {
   476→      const message = videoPollingResult.isNsfw
   477→        ? "Video blocked due to content policy"
   478→        : "Failed to generate video";
   479→      const parsedErr = parseError(message);
   480→      const cfg = {
   481→        nsfw: {
   482→          icon: "🚫",
   483→          title: "Content Policy",
   484→          bgColor: "bg-orange-500/10",
   485→          borderColor: "border-orange-500/20",
   486→          textColor: "text-orange-400",
   487→        },
   488→        unexpected_error: {
   489→          icon: "⚠",
   490→          title: "Error",
   491→          bgColor: "bg-red-500/10",
   492→          borderColor: "border-red-500/20",
   493→          textColor: "text-red-400",
   494→        },
   495→        insufficient_credits: {
   496→          icon: "⚠",
   497→          title: "Error",
   498→          bgColor: "bg-red-500/10",
   499→          borderColor: "border-red-500/20",
   500→          textColor: "text-red-400",
   501→        },
   502→      }[parsedErr.type];
   503→      return (
   504→        <div
   505→          className={`rounded-lg border ${cfg.borderColor} ${cfg.bgColor} p-3`}
   506→        >
   507→          <div className="flex items-start gap-2">
   508→            <span className={cfg.textColor}>{cfg.icon}</span>
   509→            <div className="flex-1">
   510→              <p className={`font-medium ${cfg.textColor} text-sm`}>
   511→                {cfg.title}
   512→              </p>
   513→              <p className={`mt-1 ${cfg.textColor} text-sm`}>
   514→                {parsedErr.message}
   515→              </p>
   516→            </div>
   517→          </div>
   518→        </div>
   519→      );
   520→    }
   521→
   522→    const isComplete =
   523→      videoPollingResult.videoUrl && !videoPollingResult.isLoading;
   524→    const objectId = toolCallId ? `${toolCallId}-0` : undefined;
   525→
   526→    if (isComplete && videoPollingResult.videoUrl) {
   527→      // Show final video when polling completes
   528→      return (
   529→        <div className="space-y-2">
   530→          <VideoMediaRenderer
   531→            objectIds={objectId ? [objectId] : undefined}
   532→            onVideoClick={handleMediaClick}
   533→            urls={[videoPollingResult.videoUrl]}
   534→          />
   535→          <span className="">Video added to canvas</span>
   536→        </div>
   537→      );
   538→    }
   539→
   540→    // Show placeholder while polling
   541→    return (
   542→      <div className="space-y-2">
   543→        <VideoPollingPlaceholder />
   544→        <span className="">Video will be added to canvas when ready</span>
   545→      </div>
   546→    );
   547→  }
   548→
   549→  // ─── Image Polling: Show placeholder or final image ────────────────────────
   550→  if (imagePollingData && state === "output-available") {
   551→    if (imagePollingResult.isError) {
   552→      const message = imagePollingResult.isNsfw
   553→        ? "Image blocked due to content policy"
   554→        : "Failed to generate image";
   555→      const parsedErr = parseError(message);
   556→      const cfg = {
   557→        nsfw: {
   558→          icon: "🚫",
   559→          title: "Content Policy",
   560→          bgColor: "bg-orange-500/10",
   561→          borderColor: "border-orange-500/20",
   562→          textColor: "text-orange-400",
   563→        },
   564→        unexpected_error: {
   565→          icon: "⚠",
   566→          title: "Error",
   567→          bgColor: "bg-red-500/10",
   568→          borderColor: "border-red-500/20",
   569→          textColor: "text-red-400",
   570→        },
   571→        insufficient_credits: {
   572→          icon: "⚠",
   573→          title: "Error",
   574→          bgColor: "bg-red-500/10",
   575→          borderColor: "border-red-500/20",
   576→          textColor: "text-red-400",
   577→        },
   578→      }[parsedErr.type];
   579→      return (
   580→        <div
   581→          className={`rounded-lg border ${cfg.borderColor} ${cfg.bgColor} p-3`}
   582→        >
   583→          <div className="flex items-start gap-2">
   584→            <span className={cfg.textColor}>{cfg.icon}</span>
   585→            <div className="flex-1">
   586→              <p className={`font-medium ${cfg.textColor} text-sm`}>
   587→                {cfg.title}
   588→              </p>
   589→              <p className={`mt-1 ${cfg.textColor} text-sm`}>
   590→                {parsedErr.message}
   591→              </p>
   592→            </div>
   593→          </div>
   594→        </div>
   595→      );
   596→    }
   597→
   598→    const isComplete =
   599→      imagePollingResult.imageUrl && !imagePollingResult.isLoading;
   600→    const objectId = toolCallId ? `${toolCallId}-0` : undefined;
   601→
   602→    // Generate deterministic S3 URL as fallback
   603→    // Note: Uses current date, so works best for same-day messages
   604→    const s3Key = generateS3KeyFromPredictionId(
   605→      imagePollingData.predictionId,
   606→      "image-generation",
   607→      0,
   608→      ".webp",
   609→    );
   610→    const s3FallbackUrl = generateCloudFrontUrl(s3Key);
   611→
   612→    if (isComplete && imagePollingResult.imageUrl) {
   613→      // Show final image - try Replicate URL first, fall back to S3
   614→      return (
   615→        <div className="space-y-2">
   616→          <div className="overflow-hidden rounded-xl">
   617→            <ImageWithFallback
   618→              alt="Generated image"
   619→              className="h-auto w-full cursor-pointer rounded-xl object-contain transition-opacity hover:opacity-90"
   620→              fallbackUrl={s3FallbackUrl}
   621→              height={720}
   622→              onClick={() => {
   623→                if (objectId) handleMediaClick(objectId, 0);
   624→              }}
   625→              primaryUrl={imagePollingResult.imageUrl}
   626→              sizes="(max-width: 768px) 100vw, 672px"
   627→              width={1280}
   628→            />
   629→          </div>
   630→          <span className="">Image added to canvas</span>
   631→        </div>
   632→      );
   633→    }
   634→
   635→    // Show placeholder while polling
   636→    return (
   637→      <div className="space-y-2">
