   644→  // ─── Images: Render in chat + show canvas confirmation ───────
   645→  if (media?.type === "image" && state === "output-available") {
   646→    return (
   647→      <div className="space-y-2">
   648→        <ImageMediaRenderer
   649→          objectIds={media.objectIds}
   650→          onImageClick={handleMediaClick}
   651→          urls={media.urls}
   652→        />
   653→        <span className="">
   654→          {media.urls.length} image{media.urls.length > 1 ? "s" : ""} added to
   655→          canvas
   656→        </span>
   657→      </div>
   658→    );
   659→  }
   660→
   661→  // ─── Videos: Render in chat + show canvas confirmation ───────
   662→  if (media?.type === "video" && state === "output-available") {
   663→    return (
   664→      <div className="space-y-2">
   665→        <VideoMediaRenderer
   666→          objectIds={media.objectIds}
   667→          onVideoClick={handleMediaClick}
   668→          urls={media.urls}
   669→        />
   670→        <span className="">
   671→          {media.urls.length} video{media.urls.length > 1 ? "s" : ""} added to
   672→          canvas
   673→        </span>
   674→      </div>
   675→    );
   676→  }
   677→
   678→  // ─── Fallback: Non-media output ────────────────────────────
   679→  return <ToolOutput errorText={errorText} output={output} />;
   680→};
   681→
   682→export default CustomToolOutput;
