   225→/**
   226→ * Error type classification for agent chat errors
   227→ */
   228→export type ErrorType = "insufficient_credits" | "nsfw" | "unexpected_error";
   229→
   230→/**
   231→ * Parsed error information with type and user-friendly message
   232→ */
   233→export type ParsedError = {
   234→  type: ErrorType;
   235→  message: string;
   236→};
   237→
   238→const INSUFFICIENT_CREDITS_PATTERNS = [
   239→  /insufficient.*credit/i,
   240→  /not enough.*credit/i,
   241→  /credit.*balance.*low/i,
   242→  /insufficient.*fund/i,
   243→  /payment.*required/i,
   244→  /credit.*required/i,
   245→];
   246→
   247→const NSFW_PATTERNS = [
   248→  /nsfw/i,
   249→  /not safe for work/i,
   250→  /flagged as sensitive/i,
   251→  /sensitive content/i,
   252→  /inappropriate content/i,
   253→  /content policy/i,
   254→  /safety guidelines/i,
   255→  /content filter/i,
   256→  /content moderation/i,
   257→  /safety filter/i,
   258→  /content violation/i,
   259→  /adult content/i,
   260→  /explicit content/i,
   261→  /sexual content/i,
   262→  /pornographic/i,
   263→  /nudity/i,
   264→  /violates.*policy/i,
   265→  /against.*guidelines/i,
   266→  /content.*blocked/i,
   267→  /request.*blocked/i,
   268→  /generation.*blocked/i,
   269→  /input.*rejected/i,
   270→  /output.*rejected/i,
   271→  /prompt.*rejected/i,
   272→  /e005/i, // Replicate error code
   273→];
   274→
   275→/**
   276→ * Extract error message from tool output object
   277→ * Checks multiple possible error locations in the output structure
   278→ */
   279→export function extractErrorFromOutput(output: unknown): string | null {
   280→  if (!output || typeof output !== "object") return null;
   281→
   282→  const outputObj = output as Record<string, unknown>;
   283→
   284→  // Check if output indicates failure
   285→  if (outputObj.success === false || outputObj.error) {
   286→    // Prioritize raw_response.message as it contains the most specific error
   287→    // Then fall back to other error locations
   288→    const rawResponse =
   289→      outputObj.raw_response && typeof outputObj.raw_response === "object"
   290→        ? (outputObj.raw_response as Record<string, unknown>)
   291→        : null;
   292→
   293→    const errorMessage =
   294→      (rawResponse?.message as string) ||
   295→      (outputObj.message as string) ||
   296→      (outputObj.error as string) ||
   297→      null;
   298→
   299→    return errorMessage;
   300→  }
   301→
   302→  return null;
   303→}
   304→
   305→/**
   306→ * Parse error text/JSON and extract error type and user-friendly message
   307→ * Handles both raw JSON strings and plain text error messages
   308→ */
   309→export function parseError(errorText: string | undefined | null): ParsedError {
   310→  if (!errorText) {
   311→    return {
   312→      type: "unexpected_error",
   313→      message: "An unexpected error occurred. Please try again.",
   314→    };
   315→  }
   316→
   317→  let errorMessage = errorText;
   318→  let errorObj: Record<string, unknown> | null = null;
   319→
   320→  // Try to parse as JSON if it looks like JSON
   321→  if (errorText.trim().startsWith("{") || errorText.trim().startsWith("[")) {
   322→    try {
   323→      errorObj = JSON.parse(errorText) as Record<string, unknown>;
   324→      // Extract error message from common JSON error formats
   325→      if (errorObj && typeof errorObj === "object") {
   326→        errorMessage =
   327→          (errorObj.error as string) ||
   328→          (errorObj.message as string) ||
   329→          (errorObj.detail as string) ||
   330→          errorText;
   331→      }
   332→    } catch {
   333→      // Not valid JSON, use original text
   334→      errorMessage = errorText;
   335→    }
   336→  }
   337→
   338→  // Normalize error message to lowercase for pattern matching
   339→  const normalizedMessage = errorMessage.toLowerCase();
   340→
   341→  // Check for insufficient credits errors
   342→  if (INSUFFICIENT_CREDITS_PATTERNS.some((pattern) => pattern.test(normalizedMessage))) {
   343→    return {
   344→      type: "insufficient_credits",
   345→      message: "You don't have enough credits to complete this request. Please purchase more credits to continue.",
   346→    };
   347→  }
   348→
   349→  // Check for NSFW/sensitive content errors
   350→  if (NSFW_PATTERNS.some((pattern) => pattern.test(normalizedMessage))) {
   351→    return {
   352→      type: "nsfw",
   353→      message: "The input or output was flagged as sensitive. Please try again with different content.",
   354→    };
   355→  }
   356→
   357→  // Default to unexpected error
   358→  return {
   359→    type: "unexpected_error",
   360→    message: errorMessage.length > 200
   361→      ? "An unexpected error occurred. Please try again."
   362→      : errorMessage,
   363→  };
   364→}
