     1→import { useMutation } from "@tanstack/react-query";
     2→import { useCallback, useRef } from "react";
     3→import { useCanvasAgentBridge } from "@/state/stores/canvasAgentBridge";
     4→import { useTRPC } from "@/trpc/client";
     5→import { useQueryClient } from "@tanstack/react-query";
     6→
     7→export type LocalChat = {
     8→  id: string;
     9→  title: string;
    10→  createdAt: Date;
    11→  lastUsedAt: Date;
    12→};
    13→
    14→type UseAgentChatParams<TMessage = unknown> = {
    15→  projectId: string;
    16→  activeChatId: string | null;
    17→  setActiveChatId: (id: string | null) => void;
    18→  setMessages: (messages: TMessage[] | ((prev: TMessage[]) => TMessage[])) => void;
    19→  setLocalNewChats: React.Dispatch<React.SetStateAction<LocalChat[]>>;
    20→  setCurrenttab: (tab: "chat" | "assets" | "history") => void;
    21→  allChats: { id: string }[];
    22→  chatsData: { chats: { id: string }[] } | undefined;
    23→};
    24→
    25→export const useAgentChat = <TMessage = unknown>({
    26→  projectId,
    27→  activeChatId,
    28→  setActiveChatId,
    29→  setMessages,
    30→  setLocalNewChats,
    31→  setCurrenttab,
    32→  allChats,
    33→  chatsData,
    34→}: UseAgentChatParams<TMessage>) => {
    35→  const trpc = useTRPC();
    36→  const queryClient = useQueryClient();
    37→  const clearCanvasSelection = useCanvasAgentBridge(
    38→    (store) => store.clearSelection,
    39→  );
    40→
    41→  const hasSetMessagesRef = useRef(false);
    42→  const lastChatIdRef = useRef<string | null>(null);
    43→  const processedToolCallsRef = useRef<Set<string>>(new Set());
    44→  const syncedChatsRef = useRef<Set<string>>(new Set());
    45→
    46→  const deleteChatMutation = useMutation(
    47→    trpc.chat.deleteChat.mutationOptions({
    48→      onError: (error) => {
    49→        console.error("Failed to delete chat:", error);
    50→        queryClient.invalidateQueries({
    51→          queryKey: trpc.chat.getChats.queryKey({ projectId }),
    52→        });
    53→      },
    54→      onSuccess: () => {
    55→        queryClient.invalidateQueries({
    56→          queryKey: trpc.chat.getChats.queryKey({ projectId }),
    57→        });
    58→      },
    59→    }),
    60→  );
    61→
    62→  const renameChatMutation = useMutation(
    63→    trpc.chat.updateTitle.mutationOptions({
    64→      onError: (error) => {
    65→        console.error("Failed to rename chat:", error);
    66→        queryClient.invalidateQueries({
    67→          queryKey: trpc.chat.getChats.queryKey({ projectId }),
    68→        });
    69→      },
    70→    }),
    71→  );
    72→
    73→  const handleNewChat = useCallback(() => {
    74→    const newChatId = crypto.randomUUID();
    75→    const now = new Date();
    76→
    77→    const newLocalChat: LocalChat = {
    78→      id: newChatId,
    79→      title: "New Chat",
    80→      createdAt: now,
    81→      lastUsedAt: now,
    82→    };
    83→    setLocalNewChats((prev) => [newLocalChat, ...prev]);
    84→
    85→    hasSetMessagesRef.current = false;
    86→    lastChatIdRef.current = newChatId;
    87→    processedToolCallsRef.current.clear();
    88→    syncedChatsRef.current.delete(newChatId);
    89→
    90→    clearCanvasSelection();
    91→
    92→    setActiveChatId(newChatId);
    93→    setMessages([]);
    94→    setCurrenttab("chat");
    95→  }, [
    96→    setLocalNewChats,
    97→    clearCanvasSelection,
    98→    setActiveChatId,
    99→    setMessages,
   100→    setCurrenttab,
   101→  ]);
   102→
   103→  const handleSelectChat = useCallback(
   104→    (chatId: string) => {
   105→      if (chatId === activeChatId) {
   106→        return;
   107→      }
   108→
   109→      hasSetMessagesRef.current = false;
   110→      lastChatIdRef.current = chatId;
   111→      processedToolCallsRef.current.clear();
   112→
   113→      clearCanvasSelection();
   114→
   115→      setActiveChatId(chatId);
   116→      localStorage.setItem(`active-chat-${projectId}`, chatId);
   117→      setMessages([]);
   118→    },
   119→    [
   120→      activeChatId,
   121→      projectId,
   122→      clearCanvasSelection,
   123→      setActiveChatId,
   124→      setMessages,
   125→    ],
   126→  );
   127→
   128→  const handleDeleteChat = useCallback(
   129→    async (chatId: string) => {
   130→      const isLastChat = allChats.length === 1 && allChats[0].id === chatId;
   131→
   132→      setLocalNewChats((prev) => prev.filter((c) => c.id !== chatId));
   133→
   134→      if (activeChatId === chatId) {
   135→        setActiveChatId(null);
   136→        setMessages([]);
   137→
   138→        hasSetMessagesRef.current = false;
   139→        lastChatIdRef.current = null;
   140→        processedToolCallsRef.current.clear();
   141→      }
   142→
   143→      const isServerChat = chatsData?.chats?.some((c) => c.id === chatId);
   144→      if (isServerChat) {
   145→        await deleteChatMutation.mutateAsync({ chatId });
   146→      }
   147→
   148→      if (isLastChat) {
   149→        handleNewChat();
   150→      }
   151→    },
   152→    [
   153→      allChats,
   154→      activeChatId,
   155→      chatsData?.chats,
   156→      setLocalNewChats,
   157→      setActiveChatId,
   158→      setMessages,
   159→      deleteChatMutation,
   160→      handleNewChat,
   161→    ],
   162→  );
   163→
   164→  const handleRenameChat = useCallback(
   165→    async (chatId: string, title: string) => {
   166→      await renameChatMutation.mutateAsync({ chatId, title });
   167→      queryClient.invalidateQueries({
   168→        queryKey: trpc.chat.getChats.queryKey({ projectId }),
   169→      });
   170→    },
   171→    [renameChatMutation, queryClient, trpc, projectId],
   172→  );
   173→
   174→  return {
   175→    handleNewChat,
   176→    handleSelectChat,
   177→    handleDeleteChat,
   178→    handleRenameChat,
   179→    hasSetMessagesRef,
   180→    lastChatIdRef,
   181→    processedToolCallsRef,
   182→    syncedChatsRef,
   183→  };
   184→};
