   158→      messages = [...previousMessages, message];
   159→      logger.info(`User message received, total messages: ${messages.length}`);
   160→    } else if (message.role === "assistant") {
   161→      // Assistant message sent by client's sendAutomaticallyWhen
   162→      // Preserve the client's message ID for consistency
   163→      continuationMessageId = message.id;
