   170→      // Unexpected role (system, etc.)
   171→      logger.warn(`Unexpected message role: ${message.role}`);
   172→      messages = [...previousMessages, message];
   173→    }
   174→
   175→    const bestTraceInput =
   176→      extractLatestUserTextFromUiMessages(messages) ?? initialTraceInput;
   177→
   178→    updateAgentObservation({ input: bestTraceInput });
   179→    updateAgentTrace({ input: bestTraceInput });
   180→
   181→    // Validate messages against tool schemas to ensure compatibility
   182→    let validatedMessages: UIMessage[];
   183→    try {
   184→      validatedMessages = await validateUIMessages({
   185→        messages,
   186→        // biome-ignore lint/suspicious/noExplicitAny: Because we have specific tightly typed tools types
   187→        tools: mediaAgentTools as any,
   188→      });
   189→    } catch (error) {
   190→      if (error instanceof TypeValidationError) {
