   192→        logger.warn(
   193→          `Message validation failed, starting with only new message: ${error.message}`,
   194→        );
   195→        // If validation fails (e.g., old tool schemas), start fresh with just the new message
   196→        validatedMessages = [message];
   197→      } else {
   198→        throw error;
   199→      }
   200→    }
   201→
   202→    // Save user message to database immediately (before streaming)
   203→    // Assistant messages are saved in onFinish callback after streaming completes
   204→    if (message.role === "user") {
   205→      await saveChatMessage({ message, chatId: chat.id, userId });
   206→      logger.info(`User message saved: ${message.id}`);
   207→    }
   208→    // Build agent call options from request
   209→    const agentOptions: MediaAgentCallOptions = {
   210→      isAutoMode: modelSelection?.isAutoMode ?? true,
   211→      imageModel: modelSelection?.imageModel ?? null,
   212→      videoModel: modelSelection?.videoModel ?? null,
   213→      globalSystemInstructions: globalSystemInstructions?.trim(),
   214→    };
   215→
   216→    // Flush Langfuse traces after the response is sent (serverless-friendly)
   217→    after(async () => {
   218→      await langfuseSpanProcessor.forceFlush();
   219→    });
   220→
   221→    // Return agent UI stream response with createAgentUIStreamResponse
   222→    return await createAgentUIStreamResponse({
   223→      agent: mediaAgent,
   224→      uiMessages: validatedMessages,
   225→      options: agentOptions,
   226→      // Use continuation message ID for multi-step tool execution (upsert pattern)
   227→      // This ensures client receives consistent IDs across all steps
   228→      generateMessageId: () => continuationMessageId || crypto.randomUUID(),
   229→      onError: (error) => {
