   231→        if (error instanceof Error) {
   232→          logger.error(
   233→            `Stream error occurred: name=${error.name}, message=${error.message}, requestId=${requestId}, stack=${error.stack}`,
   234→          );
   235→        } else {
   236→          logger.error(
   237→            `Unknown stream error: error=${JSON.stringify(error)}, requestId=${requestId}`,
   238→          );
   239→        }
