   276→        const outputForTrace =
   277→          outputText ??
   278→          (responseMessage
   279→            ? `[assistant] ${summarizeParts(responseMessage.parts)}`
   280→            : undefined);
   281→
   282→        updateAgentObservation({
   283→          output: outputForTrace,
   284→        });
   285→
   286→        updateAgentTrace({
   287→          output: outputForTrace,
   288→        });
   289→
   290→        endActiveSpan();
   291→
   292→        // Save assistant response message to database
   293→        // Upsert will update if already exists (from previous tool-only saves)
   294→        if (responseMessage && responseMessage.parts.length > 0) {
   295→          // ID priority: responseMessage.id > continuationMessageId > new UUID
   296→          // This ensures multi-step tool executions share the same message ID
   297→          const messageId =
   298→            responseMessage.id || continuationMessageId || crypto.randomUUID();
