   312→              `Assistant message saved: ${messageToSave.id} (${messageToSave.parts.length} parts)`,
   313→            );
   314→          } catch (saveError) {
   315→            logger.error(
   316→              `Failed to save assistant message: ${saveError instanceof Error ? saveError.message : String(saveError)}`,
   317→            );
   318→          }
