   340→
   341→    updateAgentTrace({
   342→      output: errorMessage,
   343→    });
   344→
   345→    endActiveSpan();
   346→
   347→    try {
   348→      const textId = crypto.randomUUID();
   349→
   350→      const stream = createUIMessageStream<UIMessage>({
   351→        originalMessages: [message],
   352→        execute: ({ writer }) => {
   353→          writer.write({ type: "text-start", id: textId });
   354→          writer.write({
   355→            type: "text-delta",
   356→            id: textId,
   357→            delta:
   358→              "Sorry, I am not able to respond right now. Please try again later.",
   359→          });
